from collections import defaultdict, Counter
from dataclasses import dataclass, field
from datetime import datetime, timedelta

@dataclass
class RefusalMetrics:
    window_minutes: int = 5
    thresholds: dict = field(default_factory=lambda: {
        "policy": 0.10,      # alert if >10% of calls are policy refusals
        "tool_failure": 0.05, # alert if >5% are tool failures
        "capability": 0.15,   # alert if >15% are capability refusals
    })
    _counts: Counter = field(default_factory=Counter)
    _total: int = 0
    _window_start: datetime = field(default_factory=datetime.now)

    def record(self, response_status: str, response_reason: str | None) -> None:
        now = datetime.now()
        if now - self._window_start > timedelta(minutes=self.window_minutes):
            self._flush()
        self._total += 1
        if response_reason:
            self._counts[response_reason] += 1

    def _flush(self) -> None:
        if self._total > 0:
            for reason, threshold in self.thresholds.items():
                rate = self._counts.get(reason, 0) / self._total
                if rate > threshold:
                    self._alert(reason, rate, threshold)
        self._counts.clear()
        self._total = 0
        self._window_start = datetime.now()

    def _alert(self, reason: str, rate: float, threshold: float) -> None:
        print(
            f"ALERT: {reason} refusal rate {rate:.1%} exceeds threshold {threshold:.1%}. "
            f"Investigate system prompt or tool health."
        )

# Usage
metrics = RefusalMetrics()
for response in agent_responses:
    metrics.record(response.status, response.reason)

# WRONG: retry all refusals
for attempt in range(max_retries):
    response = call_agent()
    if response.status == "ok":
        break
    # This retries policy refusals too — wastes tokens and may
    # prompt the model to find a loophole on subsequent attempts

# RIGHT: only retry tool failures
response = call_agent()
if response.status != "ok":
    if response.reason == "tool_failure":
        response = retry_with_backoff(call_agent)
    # policy and capability: handle without retry
    else:
        route_to_appropriate_handler(response)

# WRONG: swallow the error and return partial success
try:
    result = call_tool()
except TimeoutError:
    result = "Transfer initiated"  # Lies — nothing was initiated

# RIGHT: structured tool failure refusal
try:
    result = call_tool()
    return AgentResponse(status="ok", action="complete", result=result)
except TimeoutError:
    return AgentResponse(
        status="refused",
        reason="tool_failure",
        action="retry",
        user_message="The banking system is temporarily unavailable.",
    )
